import { ChatFlowise } from 'flowise';
import { VectorStore } from 'flowise';

const contentFlow = new ChatFlowise({
  nodes: {
    retriever: new VectorStore({
      embeddingsPath: './brand-voice-embeddings',
      indexName: 'brand-guidelines'
    }),
    creativeAgent: new LLMChain({
      modelName: 'gpt-4',
      prompt: `Write {topic} in our brand voice using these examples: {context}`
    }),
    factChecker: new LLMChain({
      modelName: 'gpt-4',
      prompt: `Verify factual claims in draft: {draft} against sources: {context}`
    }),
    editor: new LLMChain({
      modelName: 'gpt-4',
      prompt: `Polish for SEO and tone: {content}`
    })
  },
  edges: [
    { from: 'input', to: 'retriever' },
    { from: 'retriever', to: 'creativeAgent' },
    { from: 'creativeAgent', to: 'factChecker' },
    { from: 'factChecker', to: 'editor' },
    { from: 'editor', to: 'output' }
  ]
});

const brandVoicePrompt = `
Our Brand Voice:
- Professional yet approachable
- Optimistic, solution-focused
- Uses active voice, short sentences
- Avoids jargon, explains acronyms

EXAMPLES:
{{example_1}}
{{example_2}}

TASK: Write about {topic} (400 words)
CONTEXT: {retrieved_docs}

Output ONLY the article:`;

const creativeNode = new LLMChain({
  modelName: 'gpt-4-turbo',
  promptTemplate: brandVoicePrompt,
  maxTokens: 600,
  temperature: 0.3
});

const factCheckPrompt = `
DRAFT: {{draft}}

SOURCES: {{context}}

For each factual claim in the draft:
1. Cite specific source sentence
2. Rate confidence: HIGH/MEDIUM/LOW
3. Flag contradictions

Output JSON: {claims: [{text, source, confidence, verified}]}`;

const factChecker = new CustomToolNode({
  name: 'fact_checker',
  code: async (input) => {
    const result = await llmChain.call(factCheckPrompt, input);
    return JSON.parse(result);
  }
});

const seoTool = new CustomToolNode({
  name: 'seo_optimizer',
  schema: {
    primaryKeywords: 'string[]',
    targetLength: 'number',
    readingGrade: 'number'
  },
  code: async ({ content, primaryKeywords, targetLength = 500 }) => {
    const analysis = await analyzeSEO(content, primaryKeywords);

    if (analysis.keywordDensity < 1.5 || analysis.fleschScore > 60) {
      return await llmChain.call(
        `Optimize for SEO: ${JSON.stringify(analysis)} Content: ${content}`,
        { keywords: primaryKeywords }
      );
    }
    return content;
  }
});

