import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  project: 'flowise-content-gen',
  riskProfile: 'medium'
});

const chatflow = new ChatFlowise({
  // ... your flow config
  callbacks: {
    onChainStart: async (params) => {
      await vex.startSpan({
        name: 'content_generation',
        input: params.input,
        metadata: { node: params.nodeName }
      });
    },
    onChainEnd: async (output) => {
      const span = vex.currentSpan();
      await span.end({ output });

      // Verify brand consistency
      await vex.verify([
        {
          name: 'brand_consistency',
          criteria: 'Content matches brand voice guidelines',
          value: output
        }
      ]);
    },
    onError: async (error) => {
      await vex.recordError(error);
    }
  }
});

const brandGuardrail = async (content: string, context: string[]) => {
  const span = vex.currentSpan();

  await span.verify([
    {
      name: 'brand_consistency',
      type: 'semantic_similarity',
      criteria: 'Maintains professional, optimistic brand voice',
      value: content,
      reference: context.join('\n'),
      threshold: 0.85
    },
    {
      name: 'tone_adherence',
      type: 'regex',
      criteria: 'No negative language, uses active voice',
      value: content,
      pattern: '/(won't|can't|problem|issue|fail)/gi',
      maxMatches: 0
    }
  ]);
};

const factCheckGuardrail = async (verifiedContent: any, sources: string[]) => {
  const span = vex.currentSpan();

  await span.verify([
    {
      name: 'factual_accuracy',
      type: 'structured_extraction',
      criteria: 'All claims verified against sources',
      value: verifiedContent,
      schema: {
        claims: {
          type: 'array',
          items: { properties: { verified: { const: true } } }
        }
      }
    },
    {
      name: 'originality',
      type: 'plagiarism_check',
      criteria: 'Content originality score > 90%',
      value: verifiedContent.content,
      referenceSources: sources,
      threshold: 0.90
    },
    {
      name: 'seo_compliance',
      type: 'keyword_density',
      criteria: 'Primary keywords appear 1.5-2.5%',
      value: verifiedContent.content,
      keywords: ['AI content', 'brand voice'],
      minDensity: 0.015,
      maxDensity: 0.025
    }
  ]);
};
